import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"61. Annual Leave","description":"","frontmatter":{"title":"61. Annual Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","annual-leave","preliminary"]},"headers":[],"relativePath":"ebas/mspp/leave/61-annual-leave.md","filePath":"ebas/mspp/leave/61-annual-leave.md"}'),r={name:"ebas/mspp/leave/61-annual-leave.md"};function l(i,e,s,h,d,p){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_61-annual-leave" tabindex="-1">61. Annual Leave <a class="header-anchor" href="#_61-annual-leave" aria-label="Permalink to &quot;61. Annual Leave&quot;">​</a></h1><p><strong>61.1</strong> Additional schedules Provisions additional to those prescribed by this clause apply at the following Health Services and are attached as schedules to this Agreement as detailed below.</p><p><strong>a.</strong> <a href="/eba/ebas/mspp/schedules/4-alfred-health-general-conditions.html">Schedule 4</a> Alfred Health</p><p><strong>b.</strong> <a href="/eba/ebas/mspp/schedules/8-royal-women-s-hospital-royal-children-s-hospital-general-emp.html">Schedule 8</a> Royal Women’s Hospital</p><p><strong>c.</strong> <a href="/eba/ebas/mspp/schedules/9-royal-children-s-hospital-clinical-perfusionists.html">Schedule 9</a> Royal Children’s Hospital</p><p><strong>61.2</strong> Period of Leave</p><p><strong>a.</strong> For each completed year of service with the Employer an Employee is entitled to 190 hours of paid annual leave plus the amount specified in clause 61.10.</p><p><strong>b.</strong> An Employee’s entitlement to paid annual leave accrues progressively during each year of service according to the Employee’s ordinary hours of work and accumulates from year to year.</p><p><strong>c.</strong> For the purposes of this clause, “ordinary pay” means remuneration for the Employee’s usual weekly number of hours of work calculated at the ordinary time rate of pay, including higher qualifications allowances, and over Agreement payments, if any.</p><p><strong>61.3</strong> Annual Leave Exclusive Of Public Holidays The annual leave prescribed in clause 61.2 shall be exclusive of any of the holidays prescribed by <a href="/eba/ebas/mspp/leave/80-public-holidays.html">clause 80</a> - Public holidays, and if any such holiday falls within an Employee’s period of annual leave and is observed on a day which in the case of that Employee would have been an ordinary working day there shall be added to the period of annual leave time equivalent to the ordinary time which the Employee would have worked if such day had not been a holiday.</p><p><strong>61.4</strong> Leave To Be Taken</p><p><strong>a.</strong> The annual leave provided for by this clause shall be allowed and shall be taken and, except as provided by clauses 61.7 and 61.13, payment shall not be made or accepted in lieu of annual leave.</p><p><strong>b.</strong> Annual leave shall be taken at a time determined by mutual agreement between the Employer and the Employee. The Employer must not unreasonably refuse to agree to a request by the Employee to take paid annual leave (including requests for single day absences).</p><p><strong>c.</strong> Annual leave can be taken in hourly fractions for part day periods.</p><p><strong>61.5</strong> Leave Allowed Before Due Date An Employer may allow annual leave to an Employee before the right thereto has accrued. Where leave has been granted to an Employee pursuant to this clause before the right thereto has accrued and the Employee subsequently leaves the service of the Employer before accruing annual leave equivalent to the leave allowed in advance, the Employer is entitled to deduct from the Employee any amounts owing from any remuneration payable to the Employee on termination of the employment, where authorised.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>61.6</strong> Payment For Period Of Annual Leave Each Employee before going on leave shall be paid either in advance for the period of such leave provided the period is not less than one week or as per the normal pay cycle.</p><p><strong>61.7</strong> Proportionate Leave On Termination Of Employment When employment ends, the Employer must pay the employee for any untaken paid annual leave, at the amount that would have been paid had they taken that period of leave.</p><p><strong>61.8</strong> Weekend Shift Worker Additional Leave</p><p><strong>a.</strong> Staff (including part-time staff) who work shifts in excess of 4 hours which fall on a Saturday and/or Sunday, as part of their ordinary hours, will accrue additional annual leave at the rate of 0.5 times the number of ordinary hours worked on any weekend day, up to a maximum of 38 hours additional leave in any 12-month period.</p><p><strong>b.</strong> Provided that, in the case of part-time workers who work both a Saturday and a Sunday shift on the same weekend, only one shift per weekend will attract the accrual of the additional annual leave (ie either the Saturday or Sunday shift, but not both), up to the maximum accrual of 38 hours in any 12 month period. Provided further that where a differing number of hours are worked on a Saturday and Sunday by a part-time worker on any one weekend, the longer shift will be used to calculate the accrual of additional annual leave.</p><p><strong>c.</strong> A ‘shiftworker’, as defined for the purposes of the NES, will receive additional annual leave if applicable under the NES, if that leave entitlement is more generous than the entitlement under 61.8a. Such additional leave will be in substitution for, and not in addition to, leave under 61.8a.</p><p><strong>61.9</strong> Taking Additional Annual Leave</p><p><strong>a.</strong> In relation to the administration of an Employee’s additional annual leave:</p><p><strong>(i)</strong> Where extended leave is taken (e.g. parental, personal, long service leave etc) an Employee may elect to utilise any available annual leave credits, or retain such credits until their return to duty;</p><p><strong>(ii)</strong> Where an Employee with additional leave credits under this subclause is promoted within a hospital or health service, the credits will be carried over to their employment in the new role;</p><p><strong>(iii)</strong> Where an Employee with additional leave credits under this subclause resigns or their employment is otherwise terminated, their credits will be paid out as part of their normal annual leave payments; and</p><p><strong>(iv)</strong> The additional annual leave may be taken separately, or in conjunction with another period of annual leave, at any time by mutual agreement. Provided that where there is no agreement, clause 61.4b shall apply.</p><p><strong>61.10</strong> Annual Leave loading</p><p><strong>a.</strong> For all periods of annual leave Employees shall in addition receive the higher of either:</p><p><strong>(i)</strong> a loading of 17.5% calculated on the Employee’s ordinary pay, provided that the maximum annual allowance payable shall be calculated on the base salary for Medical Scientist Grade 3, Year 2; or</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>(ii)</strong> payment for the period of annual leave calculated at their average hourly earnings (excluding overtime) over the previous 12 months, or such shorter period of service which might apply, including shift premiums and/or Saturday, Sunday and public holiday premiums, provided that for workers who work on Saturdays and/or Sundays only, or who are rostered on permanent night shift, payment for the period of annual leave shall calculated at the rate of pay that they would have earned had they been at work.</p><p><strong>b.</strong> An Employee and Employer may agree to defer payment of the annual leave loading in respect of single day absences, until at least five consecutive annual leave days are taken.</p><p><strong>61.11</strong> Termination The loading calculated according to 61.10 shall be payable on proportionate leave calculated according to 61.7.</p><p><strong>61.12</strong> Personal and Compassionate Leave Entitlement During Annual Leave</p><p><strong>a.</strong> Where an Employee qualifies for Personal or Compassionate Leave under the terms of <a href="/eba/ebas/mspp/leave/64-personal-carer-s-leave.html">clauses 64</a> or 65 of this Agreement whilst on Annual Leave and, if requested by the Employer, provides a certificate of a registered health practitioner or other evidence acceptable to the Employer, then the number of days specified in the certificate shall be deducted from any Personal or Compassionate Leave entitlement standing to the Employee’s credit, and shall be re-credited to their Annual Leave entitlement.</p><p><strong>b.</strong> The amount of Annual Leave loading received for any period of Annual Leave converted to Personal Leave in accordance with clause 61.12a shall be offset from any future entitlement to Annual Leave loading, or if the Employee resigns, from termination pay, where authorised.</p><p><strong>61.13</strong> Cashing Out of Annual Leave</p><p><strong>a.</strong> Where an Employee has accrued annual leave in excess of eight (8) weeks, then by mutual written agreement the Employer may pay the annual leave (and annual leave loading as applicable) in excess of eight weeks to the Employee as a one-off cash payment, at the rate that would have been paid had the leave been taken. Superannuation contributions will be paid by the Employer in respect of the period of annual leave to be paid out.</p><p><strong>b.</strong> Payments made in accordance with the above extinguish an Employee&#39;s right to access leave or receive further payment for the period of leave paid out.</p><p>Plain language terms: holidays, vacation, recreation leave.</p>',42)])])}const m=a(r,[["render",l]]);export{c as __pageData,m as default};
